   242	                    member = shape.asMapShape().get().getValue();
   243	                } else if (shape instanceof StructureShape || shape instanceof UnionShape) {
   244	                    member = members.get(name.getValue());
   245	                } else {
   246	                    // At this point the shape is either null or a document shape.
   247	                    member = shape;
   248	                }
   249	
   250	                codeWriter.writeInline("\n$K: ", name.getValue());
