   262	    private static final class SmithyCodeWriter extends SimpleCodeWriter {
   263	        private static final Pattern UNQUOTED_KEY_STRING = Pattern.compile("[a-zA-Z_][a-zA-Z_0-9]*");
   264	        private final String namespace;
