   268	        SmithyCodeWriter(String namespace, Model model) {
   269	            super();
   270	            this.namespace = namespace;
   271	            this.model = model;
   272	            this.imports = new HashSet<>();
   273	            trimTrailingSpaces();
   274	            trimBlankLines();
   275	            putFormatter('I', (s, i) -> formatShapeId(s));
   276	            putFormatter('K', this::optionallyQuoteKey);
