   302	        private SmithyCodeWriter writeIndent() {
   303	            setNewline("");
   304	            // We explicitly want the trailing spaces, so disable trimming for this call.
   305	            trimTrailingSpaces(false);
   306	            write("");
   307	            trimTrailingSpaces();
   308	            setNewline("\n");
   309	            return this;
