   312	        private String formatShapeId(Object value) {
   313	            if (value == null) {
   314	                return "";
   315	            }
   316	            ShapeId shapeId = ShapeId.from(String.valueOf(value));
   317	            if (!shouldWriteNamespace(shapeId)) {
   318	                return shapeId.asRelativeReference();
   319	            }
   320	            return shapeId.toString();
   321	        }
   322	
   323	        private boolean shouldWriteNamespace(ShapeId shapeId) {
   324	            if (shapeId.getNamespace().equals(namespace)) {
   325	                return false;
   326	            }
   327	            if (Prelude.isPublicPreludeShape(shapeId)) {
   328	                return conflictsWithLocalNamespace(shapeId);
   329	            }
   330	            if (shouldImport(shapeId)) {
   331	                imports.add(shapeId.withoutMember());
   332	            }
   333	            return !imports.contains(shapeId);
   334	        }
   335	
   336	        private boolean conflictsWithLocalNamespace(ShapeId shapeId) {
   337	            return model.getShape(ShapeId.fromParts(namespace, shapeId.getName())).isPresent();
   338	        }
   339	
   340	        private boolean shouldImport(ShapeId shapeId) {
   341	            return !conflictsWithLocalNamespace(shapeId)
   342	                    // It's easier to simply never import something that conflicts with the prelude, because
   343	                    // if we did then we'd have to somehow handle rewriting all existing references to the
   344	                    // prelude shape that it conflicts with.
   345	                    && !conflictsWithPreludeNamespace(shapeId)
   346	                    && !conflictsWithImports(shapeId);
   347	
   348	        }
   349	
   350	        private boolean conflictsWithPreludeNamespace(ShapeId shapeId) {
   351	            return Prelude.isPublicPreludeShape(ShapeId.fromParts(Prelude.NAMESPACE, shapeId.getName()));
   352	        }
   353	
   354	        private boolean conflictsWithImports(ShapeId shapeId) {
   355	            return imports.stream().anyMatch(importId -> importId.getName().equals(shapeId.getName()));
   356	        }
