   358	        /**
   359	         * Writes a possibly-empty list where each element is a shape id.
   360	         *
   361	         * <p>If the list is empty, nothing is written.
   362	         */
   363	        private SmithyCodeWriter writeOptionalIdList(String textBeforeList, Collection<ShapeId> shapeIds) {
   364	            if (shapeIds.isEmpty()) {
   365	                return this;
   366	            }
   367	
   368	            openBlock("$L: [", textBeforeList);
   369	            shapeIds.stream().sorted().forEach(shapeId -> write("$I", shapeId));
   370	            closeBlock("]");
   371	
   372	            return this;
   373	        }
   374	
   375	        /**
   376	         * Formatter that quotes (and escapes) a string unless it's a valid object key string.
   377	         */
   378	        private String optionallyQuoteKey(Object key, String indent) {
   379	            String formatted = AbstractCodeWriter.formatLiteral(key);
   380	            if (UNQUOTED_KEY_STRING.matcher(formatted).matches()) {
   381	                return formatted;
   382	            }
   383	            return StringUtils.escapeJavaString(formatted, indent);
   384	        }
